schema.defaultValue:
#studio-root {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  height: 100%;
}

#studio-title {
  color: var(--accent);
  font-size: 80px;
  font-weight: 900;
  margin: 0;
}

#studio-bar {
  width: 200px;
  height: 4px;
  background: white;
  margin-top: 10px;
}

// No necesitas dvEngine.register, solo define la animación:
window.renderDVGE = (frame, props, ctx) => {
  const title = ctx.root.getElementById('studio-title');
  const bar = ctx.root.getElementById('studio-bar');
  if (!title || !bar) return;

  const ip = ctx.timeline.introProgress;
  title.style.opacity = ip;
  title.style.transform = `translateY(${ctx.utils.lerp(20, 0, ip)}px)`;
  bar.style.width = `${ctx.utils.lerp(0, 400, ctx.utils.spring(ip))}px`;
};
